640: 	// Initialize memory manager
641: 	err = cm.memoryManager.Start(ctx, memorymanager.ActivePodsFunc(activePods), sourcesReady, podStatusProvider, runtimeService, containerMap.Clone())
642: 	if err != nil {
643: 		return fmt.Errorf("start memory manager error: %w", err)
644: 	}
645: 
646: 	// cache the node Info including resource capacity and
647: 	// allocatable of the node
648: 	cm.nodeInfo = node
649: 
650: 	if localStorageCapacityIsolation {
651: 		rootfs, err := cm.cadvisorInterface.RootFsInfo()
652: 		if err != nil {
653: 			return fmt.Errorf("failed to get rootfs info: %v", err)
654: 		}
655: 		for rName, rCap := range cadvisor.EphemeralStorageCapacityFromFsInfo(rootfs) {
656: 			cm.capacity[rName] = rCap
657: 		}
658: 	}
659: 
660: 	// Ensure that node allocatable configuration is valid.
661: 	if err := cm.validateNodeAllocatable(); err != nil {
662: 		return err
663: 	}
664: 
665: 	// Setup the node
666: 	if err := cm.setupNode(ctx, activePods); err != nil {
667: 		return err
668: 	}
669: 
670: 	// Don't run a background thread if there are no ensureStateFuncs.
671: 	hasEnsureStateFuncs := false
672: 	for _, cont := range cm.systemContainers {
673: 		if cont.ensureStateFunc != nil {
674: 			hasEnsureStateFuncs = true
675: 			break
676: 		}
677: 	}
678: 	if hasEnsureStateFuncs {
679: 		// Run ensure state functions every minute.
680: 		go wait.Until(func() {
681: 			for _, cont := range cm.systemContainers {
682: 				if cont.ensureStateFunc != nil {
683: 					if err := cont.ensureStateFunc(cont.manager); err != nil {
684: 						logger.Info("Failed to ensure state", "containerName", cont.name, "err", err)
685: 					}
686: 				}
687: 			}
688: 		}, time.Minute, wait.NeverStop)
689: 
690: 	}
691: 
692: 	if len(cm.periodicTasks) > 0 {
693: 		go wait.Until(func() {
694: 			for _, task := range cm.periodicTasks {
695: 				if task != nil {
696: 					task()
697: 				}
698: 			}
699: 		}, 5*time.Minute, wait.NeverStop)
700: 	}
701: 
702: 	// Starts device manager.
703: 	if err := cm.deviceManager.Start(klog.FromContext(ctx), devicemanager.ActivePodsFunc(activePods), sourcesReady, containerMap.Clone(), containerRunningSet); err != nil {
704: 		return err
705: 	}
